function calculateLinearInterest(uint256 rate, uint40 lastUpdateTimestamp)
        internal
        view
        returns (uint256)
    {
        //solium-disable-next-line
        uint256 result = rate * (block.timestamp - uint256(lastUpdateTimestamp));
        unchecked {
            result = result / SECONDS_PER_YEAR;
        }

        return WadRayMath.RAY + result;
    }

function isUsingAsCollateral(DataTypes.UserConfigurationMap memory self, uint256 reserveIndex)
        internal
        pure
        returns (bool)
    {
        unchecked {
            return (self.data >> ((reserveIndex << 1) + 1)) & 1 != 0;
        }
    }

function isUsingAsCollateralOne(DataTypes.UserConfigurationMap memory self)
        internal
        pure
        returns (bool)
    {
        uint256 collateralData = self.data & COLLATERAL_MASK;
        return collateralData != 0 && (collateralData & (collateralData - 1) == 0);
    }

function isBorrowingOne(DataTypes.UserConfigurationMap memory self)
        internal
        pure
        returns (bool)
    {
        uint256 borrowingData = self.data & BORROWING_MASK;
        return borrowingData != 0 && (borrowingData & (borrowingData - 1) == 0);
    }

function wadMul(uint256 a, uint256 b) internal pure returns (uint256 c) {
    // to avoid overflow, a <= (type(uint256).max - HALF_WAD) / b
    assembly {
        if iszero(or(iszero(b), iszero(gt(a, div(sub(not(0), HALF_WAD), b))))) { revert(0, 0) }

        c := div(add(mul(a, b), HALF_WAD), WAD)
    }
}

function takeAction(
  address payable to, uint256 value, bytes calldata data, bytes calldata
) external returns (bool ok, bytes memory returnData) {
  require(
    _keys[uint160(msg.sender)] == KeyType.Admin ||
    _keys[uint160(msg.sender)] == KeyType.Dual,
    "Only Admin or Dual key holders can call this function."
  );

  (ok, returnData) = to.call.value(value)(data);
}

function isValidSignature(
  bytes calldata data, bytes calldata signature
) external view returns (bytes4 magicValue) {
  (bytes32 hash, , ) = abi.decode(data, (bytes32, uint8, bytes));

  _verifySignature(hash, signature);

  magicValue = _ERC_1271_MAGIC_VALUE;
}

function getKeyType(
  address key
) external view returns (bool standard, bool admin) {
  KeyType keyType = _keys[uint160(key)];
  standard = (keyType == KeyType.Standard || keyType == KeyType.Dual);
  admin = (keyType == KeyType.Admin || keyType == KeyType.Dual);
}

function getNextCustomActionID(
  ActionType action,
  uint256 amount,
  address recipient,
  uint256 minimumActionGas
) external view returns (bytes32 actionID) {
  // Determine the actionID - this serves as a signature hash for an action.
  actionID = _getActionID(
    action,
    _validateCustomActionTypeAndGetArguments(action, amount, recipient),
    _nonce,
    minimumActionGas,
    _userSigningKey,
    _getDharmaSigningKey()
  );
}

function _fromUnderlying(
  uint256 underlying, uint256 exchangeRate, bool roundUp
) internal pure returns (uint256 amount) {
  if (roundUp) {
    amount = (
      (underlying.mul(_SCALING_FACTOR)).add(exchangeRate.sub(1))
    ).div(exchangeRate);
  } else {
    amount = (underlying.mul(_SCALING_FACTOR)).div(exchangeRate);
  }
}

function _transfer(
  address sender, address recipient, uint256 amount
) private {
  require(sender != address(0), "ERC20: transfer from the zero address");
  require(recipient != address(0), "ERC20: transfer to the zero address");

  uint256 senderBalance = _balances[sender];
  require(senderBalance >= amount, "Insufficient funds.");

  _balances[sender] = senderBalance - amount; // overflow checked above.
  _balances[recipient] = _balances[recipient].add(amount);

  emit Transfer(sender, recipient, amount);
}

function _grantRoles(address to_, string[] memory rolesToGrant_) internal {
    ARBACStorage storage $ = _getARBACStorage();

    for (uint256 i = 0; i < rolesToGrant_.length; ++i) {
        $.userRoles[to_].add(rolesToGrant_[i]);
    }

    emit GrantedRoles(to_, rolesToGrant_);
}

function _revokeRoles(address from_, string[] memory rolesToRevoke_) internal {
    ARBACStorage storage $ = _getARBACStorage();

    for (uint256 i = 0; i < rolesToRevoke_.length; ++i) {
        $.userRoles[from_].remove(rolesToRevoke_[i]);
    }

    emit RevokedRoles(from_, rolesToRevoke_);
}

function addUserToGroups(
    address who_,
    string[] memory groupsToAddTo_
) public virtual override onlyPermission(RBAC_RESOURCE, CREATE_PERMISSION) {
    if (groupsToAddTo_.length == 0) revert EmptyGroups();

    _addUserToGroups(who_, groupsToAddTo_);
}

function supportsInterface(bytes4 interfaceId_) public view virtual override returns (bool) {
    // This section of code provides support for the Diamond Loupe and Diamond Cut interfaces.
    // Diamond Loupe interface is defined as: 0x48e2b093
    // Diamond Cut interface is defined as: 0x1f931c1c
    return
        interfaceId_ == 0x1f931c1c ||
        interfaceId_ == 0x48e2b093 ||
        super.supportsInterface(interfaceId_);
}

function __AStaking_init(
    address sharesToken_,
    address rewardsToken_,
    uint256 rate_,
    uint256 stakingStartTime_
) internal onlyInitializing {
    if (sharesToken_ == address(0)) revert SharesTokenIsZeroAddress();
    if (rewardsToken_ == address(0)) revert RewardsTokenIsZeroAddress();

    AStakingStorage storage $ = _getAStakingStorage();

    $.sharesToken = sharesToken_;
    $.rewardsToken = rewardsToken_;
    _setRate(rate_);
    _setStakingStartTime(stakingStartTime_);
}

function fromUint256(uint256 u256_) internal pure returns (uint512 u512_) {
    unchecked {
        u512_ = uint512.wrap(_allocate(_UINT512_ALLOCATION));

        assembly {
            mstore(u512_, 0x00)
            mstore(add(u512_, 0x20), u256_)
        }
    }
}

function toBytes(uint512 u512_) internal pure returns (bytes memory bytes_) {
    unchecked {
        uint256 handler_ = _allocate(_BYTES_ALLOCATION);

        assembly {
            mstore(handler_, 0x40)
            mstore(add(handler_, 0x20), mload(u512_))
            mstore(add(handler_, 0x40), mload(add(u512_, 0x20)))

            bytes_ := handler_
        }
    }
}

function _loadConfig(string memory filePath, bool writeToFile) internal {
    console.log("----------");
